// ResailAI Webhook Validation
// Validates incoming request and extracts payload

const crypto = require('crypto');

const body = $input.all()[0].json;
const headers = body.headers || {};
const payload = body.body || body;

// Check for Bearer token in Authorization header
const authHeader = headers.authorization || headers.Authorization;
if (!authHeader || !authHeader.startsWith('Bearer ')) {
  throw new Error('ERR_AUTH_INVALID: Missing or invalid Authorization header');
}

// Extract token
const token = authHeader.substring(7);

// Validate token (in production, fetch from Laravel API)
// For now, validate against environment variable
const expectedToken = process.env.RESAILAI_WEBHOOK_SECRET || 'your-secret-token-here';

if (!crypto.timingSafeEqual(Buffer.from(token), Buffer.from(expectedToken))) {
  throw new Error('ERR_AUTH_INVALID: Invalid API token');
}

// Validate required fields
const requiredFields = ['document_id', 'supplier_id', 'company_id', 'file_path'];
for (const field of requiredFields) {
  if (!payload[field]) {
    throw new Error(`ERR_INVALID_PAYLOAD: Missing required field: ${field}`);
  }
}

// Validate callback_url is provided
if (!payload.callback_url) {
  throw new Error('ERR_INVALID_PAYLOAD: callback_url is required');
}

// Extract file extension
const filePath = payload.file_path;
const ext = filePath.split('.').pop().toLowerCase();

// Validate file type
if (!['pdf', 'jpg', 'jpeg', 'png', 'gif'].includes(ext)) {
  throw new Error(`ERR_INVALID_FILE_TYPE: File type .${ext} not supported. Only PDF and images allowed.`);
}

// Generate processing ID
const processingId = crypto.randomUUID();

return {
  json: {
    ...payload,
    processing_id: processingId,
    file_ext: ext,
    validation_timestamp: new Date().toISOString(),
    original_input: payload
  }
};

// Parse Tika response and build extraction result
const items = $input.all();
const results = [];

for (const item of items) {
  try {
    // Extract text from Tika response
    let extractedText = '';

    if (item.binary && item.binary.data) {
      extractedText = item.binary.data.toString('utf-8');
    } else if (item.json && item.json.data) {
      extractedText = item.json.data;
    } else if (typeof item.json === 'string') {
      extractedText = item.json;
    } else if (item.json && item.json.response) {
      extractedText = item.json.response;
    }

    // Validate extracted text
    if (!extractedText || extractedText.trim().length === 0) {
      throw new Error('ERR_INSUFFICIENT_DATA: Tika extracted no text from PDF');
    }

    // Build extraction result with task-like structure
    results.push({
      json: {
        document_id: item.json.document_id,
        document_type: 'pdf',
        extraction_status: 'success',
        extraction_method: 'tika',
        extracted_text: extractedText.trim(),
        text_length: extractedText.trim().length,
        processing_id: item.json.processing_id,
        file_path: item.json.file_path,
        supplier_id: item.json.supplier_id,
        company_id: item.json.company_id,
        agent_id: item.json.agent_id || null,
        callback_url: item.json.callback_url,
        extraction_timestamp: new Date().toISOString(),
        extraction_result: {
          tasks: [],
          metadata: {
            extraction_method: 'tika',
            document_type: 'pdf',
            supplier_id: item.json.supplier_id,
            company_id: item.json.company_id,
            confidence_score: 0.95,
            text_length: extractedText.trim().length,
            processing_timestamp: new Date().toISOString()
          }
        }
      }
    });
  } catch (error) {
    results.push({
      json: {
        document_id: item.json.document_id,
        document_type: 'pdf',
        extraction_status: 'error',
        error_code: error.message.includes('ERR_') ? error.message.split(':')[0] : 'ERR_EXTRACTION_FAILED',
        error_message: error.message,
        processing_id: item.json.processing_id,
        file_path: item.json.file_path,
        supplier_id: item.json.supplier_id,
        company_id: item.json.company_id,
        agent_id: item.json.agent_id || null,
        callback_url: item.json.callback_url,
        extraction_timestamp: new Date().toISOString(),
        extraction_result: null
      }
    });
  }
}

return results;

