// Build success response for n8n webhook
const items = $input.all();
const results = [];

for (const item of items) {
  const payload = item.json;

  results.push({
    json: {
      success: payload.extraction_status === 'success',
      message: payload.extraction_status === 'success'
        ? 'Extraction completed and callback sent'
        : `Extraction failed: ${payload.error_message}`,
      document_id: payload.document_id,
      processing_id: payload.processing_id,
      extraction_status: payload.extraction_status,
      extraction_method: payload.extraction_result?.metadata?.extraction_method || null,
      callback_sent: payload.extraction_status !== 'error'
    }
  });
}

return results;
